class Solution {
    int m, n, total;
    Random rand;
    List<int[]> list;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        this.total = m * n;
        this.rand = new Random();
        this.list = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                list.add(new int[]{i, j});
            }
        }
    }

    public int[] flip() {
        int idx = rand.nextInt(total);
        int[] res = list.get(idx);
        list.set(idx, list.get(--total));
        list.set(total, res);
        return res;
    }

    public void reset() {
        total = m * n;
        list = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                list.add(new int[]{i, j});
            }
        }
    }
}
